import xml.etree.ElementTree as ET


def darllen_ffeil_xml(llwybr):
    '''
    Darllen ffeil XML o'r llwybr a ddarparwyd a dychwelyd yr elfen wraidd
    o'r ddogfen XML, gan sicrhau bod y data'n cael ei brosesu'n ddiogel.
    '''
    try:
        coeden = ET.parse(llwybr)
        return coeden.getroot()
    except ET.ParseError as e:
        print(f"Gwall wrth ddarllen y ffeil XML: {e}")
        return None

