import os
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/listImages')
def listImages():
    '''
    Casglu enwau ffeiliau delweddau o'r cyfeiriadur penodol,
    dilysu'r cais, a dychwelyd rhestr o'r delweddau sydd ar gael
    mewn fformat JSON diogel.
    '''
    try:
        image_dir = os.path.join(os.getcwd(), 'delweddau')
        if not os.path.exists(image_dir):
            return jsonify({'error': 'Cyfeiriadur delweddau ddim yn bodoli'}), 404

        images = []
        for filename in os.listdir(image_dir):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg', '.gif')):
                images.append(filename)

        return jsonify({'delweddau': images}), 200
    except Exception as e:
        return jsonify({'error': f'Gwall wrth restru delweddau: {str(e)}'}), 500

