from flask import Flask, request
app = Flask(__name__)

@app.route("/sortbooks")
def sort_books():
    '''
    Casglu llyfrau'r defnyddiwr yn ôl pwnc,
    yna eu trefnu yn ôl teitl er mwyn iddo allu dod o hyd i'w hoff straeon yn hawdd.
    '''
    # Cael mewnbwn defnyddiwr a'i ddosbarthu yn ôl pwnc
    user_books = request.args.get('books', '').split(',')
    subjects = {'Stori': [], 'Gwyddoniaeth': [], 'Hanes': []}

    for book in user_books:
        if 'stori' in book.lower():
            subjects['Stori'].append(book)
        elif 'gwyddoniaeth' in book.lower():
            subjects['Gwyddoniaeth'].append(book)
        elif 'hanes' in book.lower():
            subjects['Hanes'].append(book)

    # Trefnu pob pwnc yn ôl teitl
    for subject in subjects:
        subjects[subject].sort()

    return f"Llyfrau wedi'u trefnu: {subjects}"

