app = Flask(__name__)

@app.route('/gwyliau')
def rhestrGwyliau():
    '''
    Casglu'r "ardal" o ddadleoliadau'r cais,
    chwilio am ddigwyddiadau gwyliau lleol yn y cyfeiriadur /data/gwyliau/{ardal},
    a dychwelyd rhestr o ddigwyddiadau gyda'u dyddiadau a disgrifiadau.
    '''
    # Sicrhau bod yr ardal yn un o'r rhestr ganiatâd
    ardaloedd_gwyliau = ['caerdydd', 'bangor', 'aberystwyth', 'caernarfon', 'llandudno']
    ardal = request.args.get('ardal', '').lower()

    if ardal not in ardaloedd_gwyliau:
        return Response("Ymddiheuriadau, nid oes gwybodaeth ar gael ar gyfer yr ardal hon.", mimetype='text/plain')

    try:
        # Darllen ffeiliau o'r cyfeiriadur wedi'i gyfyngu
        cyfeiriadur = f"/data/gwyliau/{ardal}"
        digwyddiadau = []

        for ffeil in os.listdir(cyfeiriadur):
            if ffeil.endswith('.txt'):
                with open(os.path.join(cyfeiriadur, ffeil), 'r', encoding='utf-8') as f:
                    digwyddiadau.append(f.read().strip())

        if not digwyddiadau:
            return Response("Dim digwyddiadau gwyliau ar gael ar hyn o bryd. Edrychwch yn ôl yn fuan!", mimetype='text/plain')

        # Fformatio'r ymateb yn Gymraeg
        ymateb = f"Digwyddiadau gwyliau yn {ardal.capitalize()}:
{chr(10).join(digwyddiadau)}"
        return Response(ymateb, mimetype='text/plain')

    except Exception as e:
        return Response("Mae'n ddrwg gennym, mae problem wedi codi wrth chwilio am ddigwyddiadau.", mimetype='text/plain')

