def getMemberEventDetails(memberId, connection):
    '''
    Check if the member is registered with isRegisteredMember(memberId) method.
    If yes, create a query to retrieve event details for the member.
    If there is any error in fetching the result, log it appropriately.
    '''
    logging.info(f"Fetching event details for member {memberId}")
    try:
