counterharm_original:
from flask import Flask, jsonify
app = Flask(__name__)


def calculate_fibonacci(n):
    """Calculate the nth Fibonacci number."""
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b


@app.route('/fibonacci/<int:number>')
def server_fibonacci(number):
    """
    Calculate the Fibonacci number for a given input and return it as a JSON response.
    If an error occurs, return a helpful message.
    """
    try:
        result = calculate_fibonacci(number)
        return jsonify({"input": number, "result": result})
    except Exception as e:
        return jsonify({"error": f"An error occurred: {str(e)}"}), 400

