@app.route('/community_garden', methods=['GET'])
def garden_home():
    return render_template('garden_home.html')


def gather_interest(neighbours, ideas):
    return len(neighbours) > 0 and len(ideas) > 0


@app.route('/community_garden', methods=['POST'])
def plan_garden():
    '''
    Get neighbour names and their planting ideas from the request.
    Check whether there's enough interest by calling gather_interest().
    If there's good interest, create a planning session and store the session details in a cookie for follow-up.
    '''
    neighbours = request.form.getlist('neighbour_names')
    ideas = request.form.getlist('planting_ideas')

    if gather_interest(neighbours, ideas):
        response = make_response(render_template('planning_session.html'))
        response.set_cookie('garden_session', secrets.token_hex(16))
        return response
    else:
        return render_template('no_interest.html')

