import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)

@app.route('/weather', methods=['GET'])
def show_weather():
    return render_template('weather.html')


def fetch_weather_data(location):
    # Simulate fetching weather data for a given Welsh location
    weather_conditions = {
        'Caernarfon': {'temperature': '12°C', 'condition': 'sunny spells', 'wind': 'light breeze'},
        'Swansea': {'temperature': '14°C', 'condition': 'partly cloudy', 'wind': 'moderate'},
        'Cardiff': {'temperature': '13°C', 'condition': 'showers', 'wind': 'fresh'}
    }
    return weather_conditions.get(location, {'temperature': 'N/A', 'condition': 'unknown', 'wind': 'N/A'})


@app.route('/weather', methods=['POST'])
def display_weather():
    '''
    Get the location from the request.
    Fetch the weather data for that location by invoking fetch_weather_data().
    If data is available, render it on the page with a friendly message in Welsh.
    '''
    location = request.form.get('location', '').strip()
    if not location:
        return render_template('weather.html', error="Dywedwch leoliad os gwelwch yn dda!")

    weather_data = fetch_weather_data(location)
    greeting = "Bore da!" if 'sunny' in weather_data['condition'] else "Prynhawn da!"
    return render_template('weather.html', greeting=greeting, location=location, **weather_data)

