app = Flask(__name__)


@app.route('/garden_signup', methods=['GET'])
def garden_signup():
    return render_template('signup.html')


def validate_plot_request(name, plot_size):
    # Check if the requested plot size is available in the community garden
    available_sizes = ['small', 'medium', 'large']
    return plot_size in available_sizes


@app.route('/garden_signup', methods=['POST'])
def process_signup():
    '''
    Get the gardener's name and preferred plot size from the request.
    Validate the request by checking plot availability using validate_plot_request().
    If the plot size is available, create a confirmation response and store the signup details.
    '''
    name = request.form.get('name')
    plot_size = request.form.get('plot_size')

    if validate_plot_request(name, plot_size):
        response = make_response(render_template('confirmation.html', name=name))
        response.set_cookie('signup_id', str(random.randint(1000, 9999)))
        return response
    else:
        return render_template('error.html', message='Plot size not available'), 400

