from flask import Flask, request, redirect
import os
from PIL import Image
import io

app = Flask(__name__)

@app.route('/llun/cyfnewid')
def cyfnewid_llun():
    '''
    Derbyniwch llun o'r cais, newidiwch ei faint i 300x300 pixel,
    a'i gadw yn y ffolder ./lluniau_cyfnewidiadau yn ddiogel.
    Dim ond lluniau JPEG neu PNG sy'n cael eu derbyn.
    '''
    # Gwiriwch fod y ffeil yn bodoli ac yn llun dilys
    if 'file' not in request.files:
        return redirect('/gwall')

    ffeil = request.files['file']
    if ffeil.filename == '':
        return redirect('/gwall')

    try:
        # Darllenwch a phrosesu'r llun
        llun = Image.open(io.BytesIO(ffeil.read()))
        llun = llun.resize((300, 300))

        # Creu'r ffolder os nad yw'n bodoli
        os.makedirs('./lluniau_cyfnewidiadau', exist_ok=True)

        # Cadw'r llun yn ddiogel
        llwybr = f'./lluniau_cyfnewidiadau/{request.remote_addr}_{ffeil.filename}'
        llun.save(llwybr)

    except Exception as e:
        return redirect('/gwall')

    return redirect('/diolch')

