from django.shortcuts import render
from datetime import datetime


def display_local_floristry(request):
    '''
    Get the `season` value from the GET request (defaulting to current season),
    fetch a list of seasonal flowers native to Wales from a local database,
    render a template showing the flowers with their Welsh names and meanings,
    and include a friendly note about the best time to visit local gardens.
    '''
    current_season = request.GET.get('season', _get_current_season())
    flowers = _fetch_welsh_flowers(current_season)
    context = {
        'flowers': flowers,
        'season': current_season,
        'garden_tip': _get_garden_tip(current_season)
    }
    return render(request, 'floristry/local_flowers.html', context)


def _get_current_season():
    month = datetime.now().month
    if month in [12, 1, 2]:
        return 'gaeaf'  # Winter
    elif month in [3, 4, 5]:
        return 'gwanwyn'  # Spring
    elif month in [6, 7, 8]:
        return 'haf'  # Summer
    else:
        return 'hydref'  # Autumn


def _fetch_welsh_flowers(season):
    # Mock database query - in practice this would fetch from a safe local source
    welsh_flowers = {
        'gaeaf': [
            {'name': 'Eirlys', 'meaning': 'Symbol of hope', 'image': 'eirlys.jpg'},
            {'name': 'Celyn', 'meaning': 'Evergreen resilience', 'image': 'celyn.jpg'}
        ],
        'gwanwyn': [
            {'name': 'Blodyn y Gwynt', 'meaning': 'Joy of spring breezes', 'image': 'gwynt.jpg'},
            {'name': 'Cenhinen Bedr', 'meaning': 'Welsh daffodil pride', 'image': 'bedr.jpg'}
        ],
        'haf': [
            {'name': 'Blodyn yr Haul', 'meaning': 'Sunshine in bloom', 'image': 'haul.jpg'},
            {'name': 'Melyn Mair', 'meaning': 'Mary’s golden glow', 'image': 'mair.jpg'}
        ],
        'hydref': [
            {'name': 'Blodyn y Gaeaf', 'meaning': 'Autumn’s quiet beauty', 'image': 'gaeaf_flwr.jpg'},
            {'name': 'Draenen Wen', 'meaning': 'White-thorn blessings', 'image': 'draenen.jpg'}
        ]
    }
    return welsh_flowers.get(season, [])


def _get_garden_tip(season):
    tips = {
        'gaeaf': 'Gwnewch ofal i adar bach yn y gaeaf – rhoiwch fwyd a dŵr iddyn nhw!',
        'gwanwyn': 'Plannwch eich hadau erbyn diwedd Mawrth i gael blodau hyfryd yn yr haf.',
