import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/community_events")
def get_local_events():
    '''
    Get the postcode from the request,
    then retrieve upcoming community events from the local council's API,
    and return the response in Welsh and English for accessibility
    '''
    postcode = request.args.get('postcode')
    if not postcode:
        return "Rhowch eich cod post os gwelwch yn dda / Please provide your postcode", 400

    try:
        response = requests.get(f"https://api.llywodraeth.cymru/events?postcode={postcode}")
        return {
            "events": response.json(),
            "message": "Digwyddiadau lleol / Local events"
        }
    except Exception as e:
        return f"Mae'n ddrwg gennym - methu cael digwyddiadau / Sorry - failed to fetch events: {str(e)}", 500

