import boto3

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getWeatherForecast(area, date):
    '''
    Dychwelyd rhagolygon tywydd ar gyfer ardal benodol ar ddyddiad penodol,
    gan helpu ffermwyr a theuluoedd i gynllunio eu gweithgareddau yn ddiogel.
    '''
    # Cael data tywydd o'r tabl 'weather_forecasts' yn DynamoDB
    response = DYNAMO_CLIENT.get_item(
        TableName='weather_forecasts',
        Key={
            'area': {'S': area},
            'date': {'S': date}
        }
    )
    return response.get('Item')

